import { Component, EventEmitter, Input, Output } from '@angular/core';
import { Course } from '@app/shared/models/course.interface';

@Component({
  selector: 'app-courses-list',
  templateUrl: './courses-list.component.html',
  styleUrls: ['./courses-list.component.scss']
})
export class CoursesListComponent {
  @Input() courses!: Course[];
  @Input() editable!: boolean;

  @Output() showCourse = new EventEmitter();
  @Output() editCourse = new EventEmitter();
  @Output() deleteCourse = new EventEmitter();

  onShowCourse(course: Course){
    this.showCourse.emit(course);
  }

  onEditCourse(course: Course){
    this.editCourse.emit(course);
  }
  onDeleteCourse(course: Course){
    this.deleteCourse.emit(course);
  }
}
<section class="courses-list" ngFor="let course of courses">
    <app-course-card
    [title]="course.title"
    [description]="course.description"
    [authors]="course.authors"
    [duration]="course.duration"
    [creationDate]="course.creationDate"
    [isEditable]="editable">
</app-course-card>
</section>
